// $input.first().json IS already-parsed Ollama response
const resp = $input.first().json;
const specText = (resp.message?.content || resp.response || '').trim();
if (!specText) throw new Error('Ollama returned empty response');

const buildData = $('Build Prompt').first().json;
const channelId = buildData.channelId || '';
const description = buildData.description || '';

return [{ json: { specText, channelId, description } }];

const https = require('https');

function httpsReq(options, body) {
  return new Promise((resolve, reject) => {
    if (Buffer.isBuffer(body)) {
      options.headers = options.headers || {};
      options.headers['Content-Length'] = body.length;
    }
    const req = https.request(options, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const text = Buffer.concat(chunks).toString();
        try { resolve(JSON.parse(text)); } catch { resolve({ _raw: text }); }
      });
    });
    req.on('error', reject);
    if (body) req.write(body);
    req.end();
  });
}

const token = $env.SLACK_BOT_TOKEN;
const { specText, channelId, description } = $input.first().json;

// Split spec into ≤2800-char chunks (Slack section text limit is 3000)
const CHUNK = 2800;
const chunks = [];
let pos = 0;
while (pos < specText.length) {
  // Try to break at a newline boundary near the chunk limit
  let end = Math.min(pos + CHUNK, specText.length);
  if (end < specText.length) {
    const nl = specText.lastIndexOf('\n', end);
    if (nl > pos + CHUNK / 2) end = nl + 1;
  }
  chunks.push(specText.slice(pos, end).trim());
  pos = end;
}

const wordCount = specText.split(/\s+/).filter(Boolean).length;
const pageEst = Math.ceil(wordCount / 250);

// Build blocks: header + meta + divider + one section per chunk + footer
const blocks = [
  { type: 'header', text: { type: 'plain_text', text: ':page_with_curl: Patent Application Specification', emoji: true } },
  { type: 'section', text: { type: 'mrkdwn',
    text: `*Invention:* ${description}\n_${wordCount.toLocaleString()} words · ~${pageEst} pages · ${chunks.length} sections_` } },
  { type: 'divider' },
  ...chunks.map(c => ({ type: 'section', text: { type: 'mrkdwn', text: c } })),
  { type: 'divider' },
  { type: 'context', elements: [{ type: 'mrkdwn',
    text: ':warning: _AI-generated draft. Have a licensed US patent attorney review and revise before filing._' }] },
];

const msgBody = JSON.stringify({ channel: channelId, blocks, unfurl_links: false });
const resp = await httpsReq({
  method: 'POST', hostname: 'slack.com',
  path: '/api/chat.postMessage',
  headers: {
    'Authorization': `Bearer ${token}`,
    'Content-Type': 'application/json',
    'Content-Length': Buffer.byteLength(msgBody),
  }
}, Buffer.from(msgBody));

if (!resp.ok) throw new Error(`chat.postMessage failed: ${JSON.stringify(resp)}`);

return [{ json: { ok: true, ts: resp.ts, channel: resp.channel, wordCount, chunks: chunks.length } }];
